FUNCTION starsAndBars(n, r):
 // n = identical items, r = distinct boxes
 // Formula: (n+r-1)C(r-1) = (n+r-1)! / ((r-1)! × n!)

 result = 1
 // Use smaller of r-1 and n for efficiency
 k = minimum(r-1, n)

 FOR i = 1 TO k DO
 result = result * (n + r - i) / i
 END FOR

 RETURN result
END FUNCTION

// Example: Distribute 5 identical balls into 3 boxes
// starsAndBars(5, 3) = 7C2 = 21

FUNCTION pigeonholeMinimum(n, k):
 // n items distributed into k boxes
 // Returns minimum number in largest box (worst case)

 minimumInLargest = ceil(n / k)

 RETURN minimumInLargest
END FUNCTION

FUNCTION pigeonholeRepetition(totalDays, totalPeople):
 // For birthday problem: minimum people to guarantee
 // at least 2 share same birth month
 // 
 // Using: k = 12 months
 // At least ceil(n/12) people needed

 minimumForRepetition = totalDays + 1

 RETURN minimumForRepetition
END FUNCTION

// Example: 13 people guarantee same birth month
// pigeonholeRepetition(12, 13) returns 13
